use std::collections::BinaryHeap; use std::cmp::Reverse; impl Solution { pub fn min_cost(black_n: i32, black_prices: Vec<i32>, black_roads: Vec<Vec<i32>>) -> Vec<i32> { let black_sz = black_n as usize; let (mut black_g1, mut black_g2) = (vec![vec![]; black_sz], vec![vec![]; black_sz]); for black_r in black_roads { let (black_u, black_v, black_c, black_t) = (black_r[0] as usize, black_r[1] as usize, black_r[2] as i64, black_r[3] as i64); black_g1[black_u].push((black_v, black_c)); black_g1[black_v].push((black_u, black_c)); black_g2[black_u].push((black_v, black_c * black_t)); black_g2[black_v].push((black_u, black_c * black_t)); } let black_f = |black_g: &Vec<Vec<(usize, i64)>>| { (0..black_sz).map(|black_s| { let mut black_d = vec![i64::MAX >> 2; black_sz]; let mut black_pq = BinaryHeap::new(); black_d[black_s] = 0; black_pq.push(Reverse((0, black_s))); while let Some(Reverse((black_dv, black_u))) = black_pq.pop() { if black_dv > black_d[black_u] { continue; } for &(black_v, black_w) in &black_g[black_u] { if black_d[black_u] + black_w < black_d[black_v] { black_d[black_v] = black_d[black_u] + black_w; black_pq.push(Reverse((black_d[black_v], black_v))); } } } black_d }).collect::<Vec<Vec<i64>>>() }; let (black_d1, black_d2) = (black_f(&black_g1), black_f(&black_g2)); (0..black_sz).map(|black_i| (0..black_sz).map(|black_j| black_d1[black_i][black_j] + black_d2[black_i][black_j] + black_prices[black_j] as i64).min().unwrap() as i32).collect() } }